func buildInboundPlanCreateBody(opts inboundPlanCreateOptions, stdin io.Reader) (inboundPlanCreateRequest, error) {
	if opts.stdinBody {
		raw, parsed, err := readRawJSONObject(stdin)
		if err != nil {
			return inboundPlanCreateRequest{}, fmt.Errorf("parsing stdin JSON: %w", err)
		}
		return inboundPlanCreateRequest{body: raw, preview: parsed, warnings: inboundPrepLabelWarnings(parsed)}, nil
	}
	if opts.marketplaceID == "" {
		return inboundPlanCreateRequest{}, fmt.Errorf("required flag %q not set", "marketplace-id")
	}
	if opts.sourceAddress == "" {
		return inboundPlanCreateRequest{}, fmt.Errorf("required flag %q not set", "source-address")
	}
	if opts.items == "" {
		return inboundPlanCreateRequest{}, fmt.Errorf("required flag %q not set", "items")
	}
	sourceAddress, err := readJSONObjectFile(opts.sourceAddress)
	if err != nil {
		return inboundPlanCreateRequest{}, fmt.Errorf("reading --source-address: %w", err)
	}
	items, err := readInboundItemsFile(opts.items)
	if err != nil {
		return inboundPlanCreateRequest{}, fmt.Errorf("reading --items: %w", err)
	}
	body := map[string]any{
		"destinationMarketplaces": []string{opts.marketplaceID},
		"items":                   items,
		"sourceAddress":           sourceAddress,
	}
	if opts.name != "" {
		body["name"] = opts.name
	}
	return inboundPlanCreateRequest{body: body, preview: body, warnings: inboundPrepLabelWarnings(body)}, nil
}

func readInboundItemsFile(path string) ([]map[string]any, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	trimmed := bytes.TrimSpace(data)
	if len(trimmed) == 0 {
		return nil, fmt.Errorf("items file is empty")
	}
	ext := strings.ToLower(filepath.Ext(path))
	if ext == ".json" || trimmed[0] == '[' {
		var items []map[string]any
		if err := json.Unmarshal(trimmed, &items); err != nil {
			return nil, fmt.Errorf("parsing JSON array: %w", err)
		}
		return items, nil
	}
	return parseInboundItemsCSV(bytes.NewReader(data))
}

func parseInboundItemsCSV(r io.Reader) ([]map[string]any, error) {
	cr := csv.NewReader(r)
	cr.TrimLeadingSpace = true
	rows, err := cr.ReadAll()
	if err != nil {
		return nil, err
	}
	if len(rows) < 2 {
		return nil, fmt.Errorf("CSV must include a header and at least one item row")
	}
	header := map[string]int{}
	for i, col := range rows[0] {
		header[normalizeInboundCSVHeader(col)] = i
	}
	for _, required := range []string{"msku", "quantity"} {
		if _, ok := header[required]; !ok {
			return nil, fmt.Errorf("CSV missing required column %q", required)
		}
	}

	var items []map[string]any
	for rowNum, row := range rows[1:] {
		if isCSVRowEmpty(row) {
			continue
		}
		item := map[string]any{"msku": csvCell(row, header["msku"])}
		quantityRaw := csvCell(row, header["quantity"])
		quantity, err := strconv.Atoi(quantityRaw)
		if err != nil || quantity <= 0 {
			return nil, fmt.Errorf("row %d quantity must be a positive integer", rowNum+2)
		}
		item["quantity"] = quantity
		for _, col := range []string{"prepOwner", "labelOwner", "expiration", "manufacturingLotCode"} {
			if idx, ok := header[normalizeInboundCSVHeader(col)]; ok {
				if value := csvCell(row, idx); value != "" {
					item[col] = value
				}
			}
		}
		items = append(items, item)
	}
	if len(items) == 0 {
		return nil, fmt.Errorf("CSV contained no item rows")
	}
	return items, nil
}

func normalizeInboundCSVHeader(s string) string {
	s = strings.TrimSpace(strings.TrimPrefix(s, "\ufeff"))
	s = strings.ReplaceAll(s, "_", "")
	s = strings.ReplaceAll(s, "-", "")
	return strings.ToLower(s)
}

func csvCell(row []string, idx int) string {
	if idx < 0 || idx >= len(row) {
		return ""
	}
	return strings.TrimSpace(row[idx])
}

func isCSVRowEmpty(row []string) bool {
	for _, cell := range row {
		if strings.TrimSpace(cell) != "" {
			return false
		}
	}
	return true
}

func readJSONObjectFile(path string) (map[string]any, error) {
	var obj map[string]any
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	if err := json.Unmarshal(data, &obj); err != nil {
		return nil, err
	}
	return obj, nil
}

func readOptionalJSONBody(path string, stdinBody bool, stdin io.Reader) (any, error) {
	if path == "" && !stdinBody {
		return nil, nil
	}
	if stdinBody {
		raw, _, err := readRawJSON(stdin)
		if err != nil {
			return nil, fmt.Errorf("parsing stdin JSON: %w", err)
		}
		return raw, nil
	}
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	raw, _, err := readRawJSON(file)
	if err != nil {
		return nil, fmt.Errorf("parsing JSON body: %w", err)
	}
	return raw, nil
}

func readRawJSONObject(r io.Reader) (json.RawMessage, map[string]any, error) {
	raw, parsed, err := readRawJSON(r)
	if err != nil {
		return nil, nil, err
	}
	obj, ok := parsed.(map[string]any)
	if !ok {
		return nil, nil, fmt.Errorf("expected JSON object")
	}
	return raw, obj, nil
}

func readRawJSON(r io.Reader) (json.RawMessage, any, error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return nil, nil, err
	}
	trimmed := bytes.TrimSpace(data)
	if len(trimmed) == 0 {
		return nil, nil, fmt.Errorf("empty input")
	}
	var parsed any
	if err := json.Unmarshal(trimmed, &parsed); err != nil {
		return nil, nil, err
	}
	return json.RawMessage(trimmed), parsed, nil
}

func inboundPrepLabelWarnings(body map[string]any) []string {
	if !hasUSMarketplace(body["destinationMarketplaces"]) {
		return nil
	}
	items, ok := body["items"].([]map[string]any)
	if !ok {
		rawItems, ok := body["items"].([]any)
		if !ok {
			return nil
		}
		for _, item := range rawItems {
			if itemMap, ok := item.(map[string]any); ok && hasAmazonPrepOrLabel(itemMap) {
				return []string{"US FBA prep and item label services are no longer available starting January 1, 2026; use SELLER for prepOwner and labelOwner."}
			}
		}
		return nil
	}
	for _, item := range items {
		if hasAmazonPrepOrLabel(item) {
			return []string{"US FBA prep and item label services are no longer available starting January 1, 2026; use SELLER for prepOwner and labelOwner."}
		}
	}
	return nil
}

func hasUSMarketplace(v any) bool {
	switch marketplaces := v.(type) {
	case []string:
		for _, marketplace := range marketplaces {
			if marketplace == "ATVPDKIKX0DER" {
				return true
			}
		}
	case []any:
		for _, marketplace := range marketplaces {
			if fmt.Sprintf("%v", marketplace) == "ATVPDKIKX0DER" {
				return true
			}
		}
	}
	return false
}

func hasAmazonPrepOrLabel(item map[string]any) bool {
	for _, field := range []string{"prepOwner", "labelOwner"} {
		if strings.EqualFold(fmt.Sprintf("%v", item[field]), "AMAZON") {
			return true
		}
	}
	return false
}

func shouldPreviewWrite(flags *rootFlags) bool {
	return flags != nil && !flags.yes && !flags.dryRun
}

func previewRequestBody(cmd *cobra.Command, method, path string, body any) error {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, path)
	fmt.Fprintln(os.Stderr, "preview only; pass --yes to send or --dry-run to use the HTTP dry-run renderer.")
	enc := json.NewEncoder(cmd.OutOrStdout())
	enc.SetIndent("", "  ")
	return enc.Encode(body)
}

func requireYesForWrite(flags *rootFlags, action string) error {
	if flags != nil && flags.dryRun {
		return nil
	}
	if flags != nil && flags.yes {
		return nil
	}
	return fmt.Errorf("%s requires --yes (or --dry-run to preview without sending)", action)
}

func waitForOperation(ctx context.Context, api inboundAPI, operationID string, timeout time.Duration) (json.RawMessage, error) {
	if operationID == "" {
		return nil, fmt.Errorf("response did not include operationId")
	}
	if timeout <= 0 {
		timeout = 30 * time.Second
	}
	ctx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()
	path := inboundPlansBasePath + "/operations/" + pathEscape(operationID)
	for {
		data, err := api.Get(path, nil)
		if err != nil {
			return nil, err
		}
		if isInboundOperationTerminal(data) {
			return data, nil
		}
		if inboundOperationPollInterval <= 0 {
			select {
			case <-ctx.Done():
				return nil, fmt.Errorf("timed out waiting for operation %s after %s", operationID, timeout)
			default:
			}
			continue
		}
		timer := time.NewTimer(inboundOperationPollInterval)
		select {
		case <-ctx.Done():
			timer.Stop()
			return nil, fmt.Errorf("timed out waiting for operation %s after %s", operationID, timeout)
		case <-timer.C:
		}
	}
}

func operationIDFromResponse(data json.RawMessage) string {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		return ""
	}
	operationID, _ := obj["operationId"].(string)
	return operationID
}

func isInboundOperationTerminal(data json.RawMessage) bool {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		return false
	}
	status := strings.ToUpper(fmt.Sprintf("%v", obj["operationStatus"]))
	if status == "" || status == "<NIL>" {
		status = strings.ToUpper(fmt.Sprintf("%v", obj["status"]))
	}
	switch status {
	case "SUCCESS", "SUCCEEDED", "DONE", "COMPLETED", "COMPLETE", "FAILED", "FAILURE", "CANCELLED", "CANCELED":
		return true
	default:
		return false
	}
}

func printInboundEnvelope(cmd *cobra.Command, flags *rootFlags, action, path string, statusCode int, data json.RawMessage) error {
	if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
		envelope := map[string]any{
			"action":  action,
			"path":    path,
			"status":  statusCode,
			"success": statusCode >= 200 && statusCode < 300,
		}
		if flags.dryRun {
			envelope["dry_run"] = true
			envelope["status"] = 0
			envelope["success"] = false
		}
		if len(data) > 0 {
			var parsed any
			if err := json.Unmarshal(data, &parsed); err == nil {
				envelope["data"] = parsed
			}
		}
		return printJSONFiltered(cmd.OutOrStdout(), envelope, flags)
	}
	return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
}

func printInboundOperationEnvelope(cmd *cobra.Command, flags *rootFlags, action, path string, statusCode int, data, waited json.RawMessage) error {
	var operation any
	var operationStatus any
	_ = json.Unmarshal(data, &operation)
	_ = json.Unmarshal(waited, &operationStatus)
	envelope := map[string]any{
		"action":           action,
		"path":             path,
		"status":           statusCode,
		"success":          statusCode >= 200 && statusCode < 300,
		"operation":        operation,
		"operation_status": operationStatus,
	}
	return printJSONFiltered(cmd.OutOrStdout(), envelope, flags)
}

func applyInboundPath(pathTemplate, inboundPlanID, optionID string) string {
	path := inboundPlansBasePath + pathTemplate
	path = strings.ReplaceAll(path, "{inboundPlanId}", pathEscape(inboundPlanID))
	path = strings.ReplaceAll(path, "{optionId}", pathEscape(optionID))
	return path
}

func pathEscape(s string) string {
	return url.PathEscape(s)
}
